use strict;
use warnings;

my $filename = $ARGV[0];

open my $fh, '<', $filename or die "Cannot open file '$filename' $!";

my %word_count;
while (my $line = <$fh>) {
    chomp $line;
    my @words = split /\s+/, lc($line);
    foreach my $word (@words) {
        $word_count{$word}++;
    }
}

close $fh;

my @sorted_words = sort { $b <=> $a } map { $_ . ': ' . $word_count{$_} } keys %word_count;
@sorted_words = @sorted_words[0..2];

print "@sorted_words\n";

#!/usr/bin/perl
use strict;
use warnings;

my $filename = shift @ARGV;

open my $fh, '<', $filename or die "Cannot open file '$filename'";

while (my $line = <$fh>) {
    chomp $line;
    my ($name, $age, $city) = split /,/;

    if ($age > 30) {
        print "$name,$age,$city\n";
    }
}

close $fh;

#!/usr/bin/perl
use strict;
use warnings;

my $filename = $ARGV[0];

open my $fh, '<', $filename or die "Could not open file '$filename' $!";

while (my $line = <$fh>) {
    chomp $line;
    if ($line =~ /\b[A-Za-z0-9._%+-]+@[A-Za-z0-9.-]+\.[A-Z|a-z]{2,}\b/g) {
        print "$line\n";
    }
}

close $fh;
